"use client";

import { type DialogProps, Dialog as DialogRoot } from "./dialog";
import { DialogAction, type DialogActionProps } from "./dialog-action";
import { DialogBody, type DialogBodyProps } from "./dialog-body";
import { DialogClose, type DialogCloseProps } from "./dialog-close";
import { DialogCloseIcon, type DialogCloseIconProps } from "./dialog-close-icon";
import {
  DialogContent,
  type DialogContentProps,
  type DialogCorners,
  dialogContentVariants,
} from "./dialog-content";
import { DialogDescription, type DialogDescriptionProps } from "./dialog-description";
import { DialogFooter, type DialogFooterProps } from "./dialog-footer";
import { DialogHeader, type DialogHeaderProps } from "./dialog-header";
import {
  DialogKeyboardHints,
  type DialogKeyboardHintsProps,
  type KeyboardHint,
} from "./dialog-keyboard-hints";
import { DialogTitle, type DialogTitleProps } from "./dialog-title";
import {
  DialogTrigger,
  type DialogTriggerProps,
  type DialogTriggerRenderProps,
} from "./dialog-trigger";

/**
 * Modal dialog with compound component architecture. Built on the native dialog element with
 * two orthogonal visual axes: frame (border or none) and corners (none, subtle, standard, bold,
 * or outset), and an optional header marker bar spanning the title and description.
 */
const Dialog = Object.assign(DialogRoot, {
  Trigger: DialogTrigger,
  Content: DialogContent,
  Header: DialogHeader,
  Title: DialogTitle,
  Description: DialogDescription,
  Body: DialogBody,
  Footer: DialogFooter,
  KeyboardHints: DialogKeyboardHints,
  Close: DialogClose,
  CloseIcon: DialogCloseIcon,
  Action: DialogAction,
});

export { Dialog, type DialogProps };
export { DialogTrigger, type DialogTriggerProps, type DialogTriggerRenderProps };
export { DialogContent, dialogContentVariants, type DialogContentProps, type DialogCorners };
export { DialogHeader, type DialogHeaderProps };
export { DialogTitle, type DialogTitleProps };
export { DialogDescription, type DialogDescriptionProps };
export { DialogBody, type DialogBodyProps };
export { DialogFooter, type DialogFooterProps };
export { DialogClose, type DialogCloseProps };
export { DialogCloseIcon, type DialogCloseIconProps };
export { DialogAction, type DialogActionProps };
export { DialogKeyboardHints, type DialogKeyboardHintsProps, type KeyboardHint };

"use client";

import { type ReactNode, useCallback, useId, useMemo, useRef, useState } from "react";
import { useControllableState } from "@/hooks/use-controllable-state";
import { DialogContext } from "./dialog-context";

/** Props for dialog. */
export interface DialogProps {
  /** Controlled open state. Pair with onOpenChange. */
  open?: boolean;
  /** Initial open state for uncontrolled usage. */
  defaultOpen?: boolean;
  /**
   * Called whenever open state changes (trigger click, Escape, backdrop click, programmatic
   * close).
   */
  onOpenChange?: (open: boolean) => void;
  /** Content rendered inside the component. */
  children: ReactNode;
}

function useIdSetRegistry() {
  const [ids, setIds] = useState<readonly string[]>([]);
  const register = useCallback((id: string) => {
    setIds((current) => (current.includes(id) ? current : [...current, id]));
  }, []);
  const unregister = useCallback((id: string) => {
    setIds((current) => current.filter((existing) => existing !== id));
  }, []);
  return [ids.length > 0, register, unregister] as const;
}

/**
 * Modal dialog with compound component architecture. Built on the native dialog element with
 * two orthogonal visual axes: frame (border or none) and corners (none, subtle, standard, bold,
 * or outset), and an optional header marker bar spanning the title and description.
 */
function DialogRoot({ open: controlledOpen, defaultOpen, onOpenChange, children }: DialogProps) {
  const [isOpen, setIsOpen] = useControllableState({
    value: controlledOpen,
    defaultValue: defaultOpen ?? false,
    onChange: onOpenChange,
  });
  const dialogId = useId();
  const triggerRef = useRef<HTMLElement>(null);
  const [hasRegisteredTitle, registerTitle, unregisterTitle] = useIdSetRegistry();
  const [hasRegisteredDescription, registerDescription, unregisterDescription] = useIdSetRegistry();

  const contextValue = useMemo(
    () => ({
      open: isOpen,
      onOpenChange: setIsOpen,
      contentId: `${dialogId}-content`,
      titleId: `${dialogId}-title`,
      descriptionId: `${dialogId}-description`,
      triggerRef,
      hasRegisteredTitle,
      hasRegisteredDescription,
      registerTitle,
      unregisterTitle,
      registerDescription,
      unregisterDescription,
    }),
    [
      isOpen,
      setIsOpen,
      dialogId,
      hasRegisteredTitle,
      hasRegisteredDescription,
      registerTitle,
      unregisterTitle,
      registerDescription,
      unregisterDescription,
    ],
  );

  return <DialogContext value={contextValue}>{children}</DialogContext>;
}

export { DialogRoot as Dialog };

"use client";

import { createContext, type MouseEventHandler, type RefObject, useContext } from "react";

/** Context value shared by dialog. */
export interface DialogContextValue {
  /** Controlled open state. Pair with onOpenChange. */
  open: boolean;
  /**
   * Called whenever open state changes (trigger click, Escape, backdrop click, programmatic
   * close).
   */
  onOpenChange: (open: boolean) => void;
  /** DOM id for content. */
  contentId: string;
  /** DOM id for title. */
  titleId: string;
  /** DOM id for description. */
  descriptionId: string;
  /** Ref for the trigger element. */
  triggerRef: RefObject<HTMLElement | null>;
  /** Whether dialog has registered title. */
  hasRegisteredTitle: boolean;
  /** Whether dialog has registered description. */
  hasRegisteredDescription: boolean;
  /** Registers title with dialog. */
  registerTitle: (registrationId: string) => void;
  /** Unregisters title from dialog. */
  unregisterTitle: (registrationId: string) => void;
  /** Registers description with dialog. */
  registerDescription: (registrationId: string) => void;
  /** Unregisters description from dialog. */
  unregisterDescription: (registrationId: string) => void;
}

/** React context backing dialog. */
export const DialogContext = createContext<DialogContextValue | undefined>(undefined);

/** Reads the dialog context. */
export function useDialogContext() {
  const context = useContext(DialogContext);
  if (!context) {
    throw new Error("Dialog compound components must be used within a Dialog");
  }
  return context;
}

/** Provides dialog dismiss behavior. */
export function useDialogDismiss<T extends HTMLElement = HTMLElement>(
  onClick?: MouseEventHandler<T>,
): MouseEventHandler<T> {
  const { onOpenChange } = useDialogContext();
  return (e) => {
    onClick?.(e);
    if (!e.defaultPrevented) onOpenChange(false);
  };
}

"use client";

import { cva, type VariantProps } from "class-variance-authority";
import {
  Children,
  type ComponentProps,
  isValidElement,
  type ReactNode,
  type RefObject,
  type SyntheticEvent,
  useCallback,
  useEffect,
  useRef,
  useState,
} from "react";
import { useFocusRestore } from "@/hooks/use-focus-restore";
import { mergeIds } from "@/lib/aria";
import { cn } from "@/lib/utils";
import { DialogShell } from "../shared/dialog-shell";
import { PortalContainerProvider } from "../shared/portal-context";
import { useDialogContext } from "./dialog-context";
import { DialogDescription } from "./dialog-description";
import { DialogTitle } from "./dialog-title";

/**
 * Modal dialog with compound component architecture. Built on the native dialog element with
 * two orthogonal visual axes: frame (border or none) and corners (none, subtle, standard, bold,
 * or outset), and an optional header marker bar spanning the title and description.
 */
export type DialogCorners = "none" | "subtle" | "standard" | "bold" | "outset";

/** Class variants for dialog content. */
export const dialogContentVariants = cva(
  "relative w-full max-h-[90vh] flex flex-col bg-background text-foreground shadow-2xl m-auto",
  {
    variants: {
      size: {
        sm: "max-w-sm",
        md: "max-w-2xl",
        lg: "max-w-4xl",
        full: "max-w-full",
      },
      frame: {
        border: "border border-border",
        none: "",
      },
    },
    defaultVariants: {
      size: "md",
      frame: "border",
    },
  },
);

const FALLBACK_DIALOG_LABEL = "Dialog";

/** Props for dialog content. */
export interface DialogContentProps
  extends VariantProps<typeof dialogContentVariants>,
    Omit<ComponentProps<"dialog">, "children" | "className"> {
  /** Content rendered inside the component. */
  children: ReactNode;
  /** Additional class names merged onto the rendered element. */
  className?: string;
  /**
   * Corner accent marks drawn at the dialog corners. "none" skips them. "subtle" uses border
   * color and tighter 12px arms. "standard" uses foreground color 18px arms. "bold" uses
   * foreground color 28px arms. "outset" is standard shifted 3px outside the dialog edge.
   * Combine with frame="none" for a pure viewfinder look or frame="border" for a
   * bracketed-frame look.
   */
  corners?: DialogCorners | null;
  /**
   * Set role="alertdialog" for destructive confirmations. Per WAI-ARIA APG, alert dialogs
   * should not close on outside interaction.
   */
  role?: "dialog" | "alertdialog";
  /** When false, clicking the backdrop does not close the dialog (recommended for alertdialog). */
  closeOnBackdropClick?: boolean;
  /** Element that receives focus when the overlay opens. */
  initialFocus?: RefObject<HTMLElement | null>;
  /** Native cancel handler. Defaults to closing the dialog. */
  onCancel?: (e: SyntheticEvent<HTMLDialogElement>) => void;
  /** Intercept Escape. Call e.preventDefault() to keep the dialog open during async operations. */
  onEscapeKeyDown?: (e: SyntheticEvent<HTMLDialogElement>) => void;
}

function hasNonEmptyText(value: unknown): value is string {
  return typeof value === "string" && value.trim().length > 0;
}

type AccessibleNameInput = {
  ariaLabel: string | undefined;
  ariaLabelledBy: string | undefined;
  titleId: string;
  hasRenderableTitle: boolean;
};

type AccessibleNameOutput = {
  "aria-label": string | undefined;
  "aria-labelledby": string | undefined;
};

function resolveAccessibleName({
  ariaLabel,
  ariaLabelledBy,
  titleId,
  hasRenderableTitle,
}: AccessibleNameInput): AccessibleNameOutput {
  if (hasNonEmptyText(ariaLabelledBy)) {
    return { "aria-label": undefined, "aria-labelledby": ariaLabelledBy };
  }
  if (hasNonEmptyText(ariaLabel)) {
    return { "aria-label": ariaLabel, "aria-labelledby": undefined };
  }
  if (hasRenderableTitle) {
    return { "aria-label": undefined, "aria-labelledby": titleId };
  }
  return { "aria-label": FALLBACK_DIALOG_LABEL, "aria-labelledby": undefined };
}

/**
 * Provide an accessible name through one of three paths (precedence order):
 *
 * 1. `aria-labelledby` pointing at existing element id(s);
 * 2. an explicit `aria-label` string;
 * 3. a rendered `<Dialog.Title>`, whose id is wired automatically.
 *
 * ```tsx
 * <Dialog.Content><Dialog.Title>Settings</Dialog.Title>…</Dialog.Content>
 * <Dialog.Content aria-label="Settings">…</Dialog.Content>
 * <Dialog.Content aria-labelledby="settings-heading">…</Dialog.Content>
 * ```
 *
 * If none are present the dialog falls back to the label "Dialog" and warns in
 * dev so the dialog still has a usable name rather than failing to open.
 */
export function DialogContent({
  children,
  className,
  size,
  frame,
  corners,
  closeOnBackdropClick = true,
  initialFocus,
  onEscapeKeyDown,
  onCancel,
  onAnimationEnd,
  "aria-label": ariaLabel,
  "aria-labelledby": ariaLabelledBy,
  "aria-describedby": ariaDescribedBy,
  ...rest
}: DialogContentProps) {
  const {
    open,
    onOpenChange,
    contentId,
    titleId,
    descriptionId,
    triggerRef,
    hasRegisteredTitle,
    hasRegisteredDescription,
  } = useDialogContext();
  const close = () => onOpenChange(false);
  const shellRef = useRef<HTMLDialogElement>(null);
  const [container, setContainer] = useState<Element | null>(null);
  const focusRestore = useFocusRestore({ restoreOnUnmount: false });
  // Restore focus to the captured opener; fall back to the trigger ref read at
  // restore time (not during render) so a programmatically-opened dialog still
  // returns focus somewhere sensible.
  const handleClose = useCallback(() => {
    if (!focusRestore.restore()) triggerRef.current?.focus();
  }, [focusRestore, triggerRef]);
  // Registration covers parts rendered through consumer wrapper components; the
  // static child scan seeds the first render before the registration effects run.
  const hasRenderableTitle = hasRegisteredTitle || containsDialogTitleElement(children);
  const hasRenderableDescription =
    hasRegisteredDescription || containsDialogDescriptionElement(children);
  const resolvedFrame = frame ?? "border";
  const resolvedCorners = corners ?? "none";
  const accessibleName = resolveAccessibleName({
    ariaLabel,
    ariaLabelledBy,
    titleId,
    hasRenderableTitle,
  });

  const isFallbackName = accessibleName["aria-label"] === FALLBACK_DIALOG_LABEL;

  useEffect(() => {
    if (process.env.NODE_ENV === "production" || !isFallbackName) return;
    // Defer to the next frame so a Title registered by a wrapper component (its
    // registration runs in a layout effect, after this render's fallback was
    // computed) clears the fallback before we warn — avoiding a false warning.
    const view = shellRef.current?.ownerDocument.defaultView ?? globalThis;
    const frame = view.requestAnimationFrame(() => {
      if (accessibleName["aria-label"] === FALLBACK_DIALOG_LABEL) {
        console.warn(
          "Dialog: No accessible name provided. Add a <Dialog.Title>, aria-label, or aria-labelledby prop.",
        );
      }
    });
    return () => view.cancelAnimationFrame(frame);
  }, [isFallbackName, accessibleName]);

  const resolvedDescribedBy = mergeIds(
    ariaDescribedBy,
    hasRenderableDescription ? descriptionId : undefined,
  );

  const setShellRef = useCallback((node: HTMLDialogElement | null) => {
    shellRef.current = node;
    setContainer(node);
  }, []);

  return (
    <DialogShell
      {...rest}
      open={open}
      id={contentId}
      dialogRef={setShellRef}
      initialFocus={initialFocus}
      onBackdropClick={closeOnBackdropClick ? close : undefined}
      onCancel={(e) => {
        onCancel?.(e);
        if (e.defaultPrevented) return;
        onEscapeKeyDown?.(e);
        if (!e.defaultPrevented) close();
      }}
      onBeforeShowModal={focusRestore.capture}
      onClose={handleClose}
      onAnimationEnd={onAnimationEnd}
      className={cn(dialogContentVariants({ size, frame }), className)}
      data-slot="dialog-content"
      data-frame={resolvedFrame}
      data-corners={resolvedCorners}
      aria-modal="true"
      aria-label={accessibleName["aria-label"]}
      aria-labelledby={accessibleName["aria-labelledby"]}
      aria-describedby={resolvedDescribedBy}
    >
      <PortalContainerProvider container={container}>
        {resolvedCorners !== "none" ? <span aria-hidden="true" className="dlg-corners" /> : null}
        {children}
      </PortalContainerProvider>
    </DialogShell>
  );
}

function containsDialogTitleElement(children: ReactNode): boolean {
  return Children.toArray(children).some((child) => {
    if (!isValidElement<{ children?: ReactNode }>(child)) return false;
    if (child.type === DialogTitle) return true;
    return containsDialogTitleElement(child.props.children);
  });
}

function containsDialogDescriptionElement(children: ReactNode): boolean {
  return Children.toArray(children).some((child) => {
    if (!isValidElement<{ children?: ReactNode }>(child)) return false;
    if (child.type === DialogDescription) return true;
    return containsDialogDescriptionElement(child.props.children);
  });
}

"use client";

import type { ComponentProps } from "react";
import { cn } from "@/lib/utils";

/** Props for dialog header. */
export interface DialogHeaderProps extends ComponentProps<"div"> {
  /**
   * Header leading marker. "bar" (default) renders a 4px foreground accent bar with flex gap-3
   * outer spacing and a nested text column. "none" is the neutral form - no bar, no gap,
   * children render as direct flex-col descendants - intended for headers with a background
   * color, horizontal title-row layouts, or custom compositions. Consumer className overrides
   * (padding, flex direction, background) merge cleanly on both variants via tailwind-merge.
   */
  marker?: "bar" | "none";
}

/** Header wrapper. */
export function DialogHeader({ className, children, marker = "bar", ...props }: DialogHeaderProps) {
  if (marker === "bar") {
    return (
      <div
        data-slot="dialog-header"
        className={cn("flex gap-3 px-5 pt-4 pb-3 shrink-0", className)}
        {...props}
      >
        <span aria-hidden="true" className="w-1 self-stretch bg-foreground" />
        <div className="flex flex-col gap-1 min-w-0 flex-1">{children}</div>
      </div>
    );
  }

  return (
    <div
      data-slot="dialog-header"
      className={cn("flex flex-col gap-1 min-w-0 px-5 pt-4 pb-3 shrink-0", className)}
      {...props}
    >
      {children}
    </div>
  );
}

"use client";

import { type ComponentProps, useId, useLayoutEffect } from "react";
import { cn } from "@/lib/utils";
import { useDialogContext } from "./dialog-context";

/** Props for dialog title. */
export interface DialogTitleProps extends ComponentProps<"h2"> {
  /** Heading level for the title element. */
  as?: "h1" | "h2" | "h3" | "h4" | "h5" | "h6";
  /**
   * Optional right-aligned eyebrow tag (e.g. "CONFIRM", "DESTRUCTIVE"). Decorative - rendered
   * aria-hidden so it does not leak into the accessible name.
   */
  meta?: string;
}

/** Accessible title. */
export function DialogTitle({
  children,
  className,
  as: Tag = "h2",
  meta,
  ...props
}: DialogTitleProps) {
  const { titleId, registerTitle, unregisterTitle } = useDialogContext();
  const registrationId = useId();

  useLayoutEffect(() => {
    registerTitle(registrationId);
    return () => unregisterTitle(registrationId);
  }, [registerTitle, unregisterTitle, registrationId]);

  // The dialog's aria-labelledby points at the heading (titleId), so the
  // accessible name is the title text alone. The meta slot renders as a sibling
  // OUTSIDE the heading: visible to AT as page content but excluded from the
  // dialog's accessible name (F-155).
  if (!meta) {
    return (
      <Tag
        {...props}
        id={titleId}
        data-slot="dialog-title"
        className={cn("flex items-center gap-2.5 text-sm font-bold text-foreground", className)}
      >
        {children}
      </Tag>
    );
  }

  return (
    <div data-slot="dialog-title-row" className="flex items-center gap-2.5">
      <Tag
        {...props}
        id={titleId}
        data-slot="dialog-title"
        className={cn("min-w-0 flex-1 truncate text-sm font-bold text-foreground", className)}
      >
        {children}
      </Tag>
      <span className="ml-auto shrink-0 text-[length:var(--dialog-title-meta-size)] font-normal uppercase tracking-[var(--dialog-title-meta-tracking)] text-muted">
        {meta}
      </span>
    </div>
  );
}

"use client";

import { type ComponentProps, useId, useLayoutEffect } from "react";
import { cn } from "@/lib/utils";
import { useDialogContext } from "./dialog-context";

/** Props for dialog description. */
export interface DialogDescriptionProps extends ComponentProps<"p"> {}

/** Accessible description. */
export function DialogDescription({ className, ...props }: DialogDescriptionProps) {
  const { descriptionId, registerDescription, unregisterDescription } = useDialogContext();
  const registrationId = useId();

  useLayoutEffect(() => {
    registerDescription(registrationId);
    return () => unregisterDescription(registrationId);
  }, [registerDescription, unregisterDescription, registrationId]);

  return (
    <p
      {...props}
      data-slot="dialog-description"
      id={descriptionId}
      className={cn("text-xs text-foreground/70", className)}
    />
  );
}

"use client";

import type { ComponentProps } from "react";
import { cn } from "@/lib/utils";

/** Props for dialog body. */
export interface DialogBodyProps extends ComponentProps<"div"> {}

/** Scrollable content. */
export function DialogBody({ className, ...props }: DialogBodyProps) {
  return (
    <div
      data-slot="dialog-body"
      className={cn("flex-1 overflow-y-auto px-5 py-5", className)}
      {...props}
    />
  );
}

"use client";

import type { ComponentProps, ReactNode } from "react";
import { cn } from "@/lib/utils";
import { DialogKeyboardHints, type KeyboardHint } from "./dialog-keyboard-hints";

export { DialogKeyboardHints, type KeyboardHint };

/** Props for dialog footer. */
export interface DialogFooterProps extends ComponentProps<"div"> {
  /**
   * Inline keyboard shortcut hints rendered alongside the action buttons. Use the shorthand
   * instead of composing DialogFooter.Hints when the hints belong with the footer actions.
   */
  hints?: KeyboardHint[];
  /** Content rendered inside the component. */
  children?: ReactNode;
}

function DialogFooterRoot({ hints, className, children, ...props }: DialogFooterProps) {
  const hasHints = hints && hints.length > 0;

  return (
    <div
      data-slot="dialog-footer"
      className={cn(
        "flex gap-3 items-center px-5 pt-3 pb-4 shrink-0 bg-background text-foreground",
        hasHints ? "justify-between" : "justify-end",
        className,
      )}
      {...props}
    >
      {hasHints ? <DialogKeyboardHints hints={hints} /> : null}
      {children ? <DialogFooterActions>{children}</DialogFooterActions> : null}
    </div>
  );
}

/** Props for dialog footer actions. */
export type DialogFooterActionsProps = ComponentProps<"div">;

function DialogFooterActions({ className, ...props }: DialogFooterActionsProps) {
  return (
    <div className={cn("flex shrink-0 items-center justify-end gap-3", className)} {...props} />
  );
}

/** Action buttons and optional keyboard hints. */
export const DialogFooter: typeof DialogFooterRoot & {
  Hints: typeof DialogKeyboardHints;
  Actions: typeof DialogFooterActions;
} = Object.assign(DialogFooterRoot, {
  Hints: DialogKeyboardHints,
  Actions: DialogFooterActions,
});

"use client";

import type { ComponentProps } from "react";
import { cn } from "@/lib/utils";
import { Kbd } from "../kbd/kbd";

/**
 * Modal dialog with compound component architecture. Built on the native dialog element with
 * two orthogonal visual axes: frame (border or none) and corners (none, subtle, standard, bold,
 * or outset), and an optional header marker bar spanning the title and description.
 */
export interface KeyboardHint {
  /** key used by keyboard hint. */
  key: string;
  /** Accessible label text. */
  label: string;
}

/** Props for dialog keyboard hints. */
export interface DialogKeyboardHintsProps extends ComponentProps<"div"> {
  /** hints used by dialog keyboard hints. */
  hints: KeyboardHint[];
  /** Size variant. */
  size?: "sm" | "md";
}

/**
 * Modal dialog with compound component architecture. Built on the native dialog element with
 * two orthogonal visual axes: frame (border or none) and corners (none, subtle, standard, bold,
 * or outset), and an optional header marker bar spanning the title and description.
 */
export function DialogKeyboardHints({
  hints,
  size = "md",
  className,
  ...props
}: DialogKeyboardHintsProps) {
  if (!hints.length) return null;

  return (
    <div
      className={cn("flex min-w-0 flex-wrap items-center gap-x-3 gap-y-1 text-xs", className)}
      {...props}
    >
      {hints.map((hint) => (
        <span key={`${hint.key}-${hint.label}`} className="inline-flex items-center gap-1">
          {/* Key name stays exposed to AT (no aria-hidden) so keyboard users can
              discover the shortcut — CommandPaletteInput's Kbd is the model. */}
          <Kbd size={size}>{hint.key}</Kbd>
          <span>{hint.label}</span>
        </span>
      ))}
    </div>
  );
}

"use client";

import type { FocusEventHandler, MouseEventHandler, ReactNode, Ref } from "react";
import { Button, type ButtonProps } from "../button/button";
import { useDialogDismiss } from "./dialog-context";

/** Props for dialog close. */
export interface DialogCloseProps
  extends Pick<
    ButtonProps,
    "variant" | "size" | "bracket" | "className" | "disabled" | "highlighted"
  > {
  /** Content rendered inside the component. */
  children?: ReactNode;
  /** Close handler. Call e.preventDefault() to keep the dialog open. */
  onClick?: MouseEventHandler<HTMLButtonElement>;
  /** Called when focus occurs. */
  onFocus?: FocusEventHandler<HTMLButtonElement>;
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLButtonElement>;
  /** Moves focus to the element when it mounts. */
  autoFocus?: boolean;
  [dataAttribute: `data-${string}`]: unknown;
}

/** Close button. */
export function DialogClose({
  children,
  onClick,
  variant = "ghost",
  ref,
  ...buttonProps
}: DialogCloseProps) {
  const handleClick = useDialogDismiss(onClick);

  return (
    <Button
      ref={ref}
      type="button"
      {...buttonProps}
      variant={variant}
      aria-label={!children ? "Close dialog" : undefined}
      onClick={handleClick}
    >
      {children ?? "[x]"}
    </Button>
  );
}

"use client";

import type { ComponentProps, Ref } from "react";
import { cn } from "@/lib/utils";
import { useDialogDismiss } from "./dialog-context";

/** Props for dialog close icon. */
export interface DialogCloseIconProps
  extends Omit<ComponentProps<"button">, "type" | "children" | "aria-label" | "ref"> {
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLButtonElement>;
  /** Accessible name for the close button. Override for localization or alternative phrasing. */
  "aria-label"?: string;
}

/**
 * Optional top-right close button - render LAST inside DialogContent so DOM/Tab order is
 * correct (it absolute-positions itself)
 */
export function DialogCloseIcon({
  ref,
  className,
  onClick,
  "aria-label": ariaLabel = "Close dialog",
  ...props
}: DialogCloseIconProps) {
  const handleClick = useDialogDismiss<HTMLButtonElement>(onClick);

  return (
    <button
      ref={ref}
      type="button"
      data-slot="dialog-close-icon"
      aria-label={ariaLabel}
      className={cn(
        "absolute top-[var(--dialog-close-btn-inset)] right-[var(--dialog-close-btn-inset)] z-10",
        "inline-flex items-center justify-center w-7 h-7 rounded-sm font-mono text-base leading-none",
        "text-muted-foreground hover:text-foreground transition-colors cursor-pointer",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary focus-visible:ring-offset-2 focus-visible:ring-offset-background",
        className,
      )}
      onClick={handleClick}
      {...props}
    >
      ×
    </button>
  );
}

"use client";

import type { FocusEventHandler, MouseEventHandler, ReactNode, Ref } from "react";
import { Button, type ButtonProps } from "../button/button";
import { useDialogDismiss } from "./dialog-context";

/** Props for dialog action. */
export interface DialogActionProps
  extends Pick<
    ButtonProps,
    "variant" | "size" | "bracket" | "className" | "disabled" | "loading" | "highlighted"
  > {
  /** Content rendered inside the component. */
  children: ReactNode;
  /**
   * Primary action handler. Call e.preventDefault() to keep the dialog open (e.g. failed form
   * validation).
   */
  onClick?: MouseEventHandler<HTMLButtonElement>;
  /** Called when focus occurs. */
  onFocus?: FocusEventHandler<HTMLButtonElement>;
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLButtonElement>;
  /** Moves focus to the element when it mounts. */
  autoFocus?: boolean;
  [dataAttribute: `data-${string}`]: unknown;
}

/** Primary action button (closes unless prevented) */
export function DialogAction({
  children,
  onClick,
  variant = "action",
  bracket = true,
  ref,
  ...props
}: DialogActionProps) {
  const handleClick = useDialogDismiss(onClick);

  return (
    <Button
      ref={ref}
      type="button"
      {...props}
      variant={variant}
      bracket={bracket}
      onClick={handleClick}
    >
      {children}
    </Button>
  );
}

"use client";

import {
  type ComponentPropsWithRef,
  cloneElement,
  isValidElement,
  type MouseEventHandler,
  type ReactElement,
  type ReactNode,
  type Ref,
  type RefCallback,
} from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import { cn } from "@/lib/utils";
import { useDialogContext } from "./dialog-context";

/** Props for dialog trigger render. */
export interface DialogTriggerRenderProps {
  /** Ref forwarded to the underlying element. */
  ref: RefCallback<HTMLElement>;
  /** Additional class names merged onto the rendered element. */
  className?: string;
  /** ARIA popup type forwarded to the rendered element. */
  "aria-haspopup": "dialog";
  /** ARIA expanded state forwarded to the rendered element. */
  "aria-expanded": boolean;
  /** ID of the element controlled by the rendered element. */
  "aria-controls": string;
  /** Called when click occurs. */
  onClick: MouseEventHandler<HTMLElement>;
}

/** Props for dialog trigger. */
export interface DialogTriggerProps {
  /**
   * Trigger button or render function. The render form receives ref, className,
   * aria-haspopup/expanded/controls, and onClick.
   */
  children: ReactNode | ((props: DialogTriggerRenderProps) => ReactNode);
  /** Additional class names merged onto the rendered element. */
  className?: string;
  /** Called when click occurs. */
  onClick?: MouseEventHandler<HTMLElement>;
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLElement>;
}

/** Props for dialog trigger element. */
interface DialogTriggerElementProps {
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLElement>;
  /** Additional class names merged onto the rendered element. */
  className?: string;
  /** Selection mode. */
  type?: string;
  /** ARIA popup type forwarded to the rendered element. */
  "aria-haspopup"?: "dialog";
  /** ARIA expanded state forwarded to the rendered element. */
  "aria-expanded"?: boolean;
  /** ID of the element controlled by the rendered element. */
  "aria-controls"?: string;
  /** Called when click occurs. */
  onClick?: MouseEventHandler<HTMLElement>;
}

const nativeInteractiveElements = new Set([
  "button",
  "a",
  "input",
  "select",
  "textarea",
  "summary",
]);

function isNativeInteractiveElement(element: ReactElement<DialogTriggerElementProps>): boolean {
  return typeof element.type === "string" && nativeInteractiveElements.has(element.type);
}

function mergeClickHandlers(
  existing: MouseEventHandler<HTMLElement> | undefined,
  added: MouseEventHandler<HTMLElement>,
): MouseEventHandler<HTMLElement> {
  return (event) => {
    existing?.(event);
    if (!event.defaultPrevented) added(event);
  };
}

/** Opens the dialog. */
export function DialogTrigger({ children, className, onClick, ref }: DialogTriggerProps) {
  const { open, onOpenChange, contentId, triggerRef } = useDialogContext();
  const childRef = isValidElement<DialogTriggerElementProps>(children)
    ? children.props.ref
    : undefined;
  const composedRef = useComposedRefs(triggerRef, ref, childRef);

  const handleClick: MouseEventHandler<HTMLElement> = (e) => {
    onClick?.(e);
    if (!e.defaultPrevented) onOpenChange(true);
  };

  const triggerProps: DialogTriggerRenderProps = {
    ref: composedRef,
    className,
    "aria-haspopup": "dialog",
    "aria-expanded": open,
    "aria-controls": contentId,
    onClick: handleClick,
  };

  if (typeof children === "function") return <>{children(triggerProps)}</>;

  if (isValidElement<DialogTriggerElementProps>(children)) {
    const child = children as ReactElement<DialogTriggerElementProps>;
    if (isNativeInteractiveElement(child)) {
      const buttonType = child.type === "button" ? { type: child.props.type ?? "button" } : {};

      return cloneElement(child, {
        ...buttonType,
        ref: composedRef,
        className: cn(child.props.className, className),
        "aria-haspopup": triggerProps["aria-haspopup"],
        "aria-expanded": triggerProps["aria-expanded"],
        "aria-controls": triggerProps["aria-controls"],
        onClick: mergeClickHandlers(child.props.onClick, triggerProps.onClick),
      });
    }
  }

  const buttonProps = triggerProps satisfies ComponentPropsWithRef<"button">;
  return (
    <button type="button" {...buttonProps}>
      {children}
    </button>
  );
}
